mapper.select:
select c.id, c.name, c.room, c.begin_date beginDate, c.end_date endDate, c.master_id masterId, c.create_time createTime, c.update_time updateTime, e.name masterName, case when c.begin_date > curdate() then '未开班' when c.end_date < curdate() then '已结课' else '在读' end status from clazz c left join emp e on c.master_id = e.id
and c.name like concat('%', #{name}, '%')
and c.begin_date >= #{begin}
and c.end_date <= #{end}
order by c.update_time desc
